mcp = {
    "name": "MCP",
    "open_spec": True,
    "multi_client": True,
    "low_publisher_bar": True,
    "primitive_not_marketplace": True,
}

openai_plugins = {
    "name": "OpenAI Plugins",
    "open_spec": False,
    "multi_client": False,
    "low_publisher_bar": False,
    "primitive_not_marketplace": False,
}

def audit_protocol(spec):
    signals = [
        "open_spec",
        "multi_client",
        "low_publisher_bar",
        "primitive_not_marketplace",
    ]
    score = 0
    for s in signals:
        if spec.get(s):
            score += 25
    if score >= 75:
        verdict = "will-win"
    elif score >= 50:
        verdict = "maybe"
    elif score >= 25:
        verdict = "niche"
    else:
        verdict = "dead-on-arrival"
    return {"score": score, "verdict": verdict}

print(f"MCP:            {audit_protocol(mcp)}")
print(f"OpenAI Plugins: {audit_protocol(openai_plugins)}")

protocols = [
    {"name": "OpenAI Plugins",        "open_spec": False, "multi_client": False, "low_publisher_bar": False, "primitive_not_marketplace": True},
    {"name": "MCP",                   "open_spec": True,  "multi_client": True,  "low_publisher_bar": True,  "primitive_not_marketplace": True},
    {"name": "ChatGPT Actions",       "open_spec": False, "multi_client": False, "low_publisher_bar": False, "primitive_not_marketplace": False},
    {"name": "LangChain Tools",       "open_spec": True,  "multi_client": False, "low_publisher_bar": True,  "primitive_not_marketplace": True},
    {"name": "GitHub Copilot Skills", "open_spec": False, "multi_client": False, "low_publisher_bar": True,  "primitive_not_marketplace": True},
]

SIGNALS = [
    "open_spec",
    "multi_client",
    "low_publisher_bar",
    "primitive_not_marketplace",
]

def score(p):
    return sum(25 for s in SIGNALS if p.get(s))

def verdict_for(s):
    if s >= 75:
        return "will-win"
    if s >= 50:
        return "maybe"
    if s >= 25:
        return "niche"
    return "dead-on-arrival"

def rank_protocols(protocols):
    ordered = sorted(protocols, key=score, reverse=True)
    return {p["name"]: verdict_for(score(p)) for p in ordered}

ranked = rank_protocols(protocols)
for name, verdict in ranked.items():
    print(f"{name}: {verdict}")
